/**
 * E-Menum Application Entry Point
 *
 * Main entry point for the E-Menum Enterprise QR Menu Platform.
 * Initializes the application, creates the Express server, and starts listening.
 *
 * Startup Flow:
 * 1. Import reflect-metadata (required for tsyringe DI)
 * 2. Validate environment configuration
 * 3. Bootstrap application (database, cache, modules)
 * 4. Create and configure Express server
 * 5. Register middleware stack
 * 6. Mount module routes
 * 7. Start HTTP server
 *
 * @module main
 */

// reflect-metadata must be imported first for tsyringe DI to work
import 'reflect-metadata';

import express, { Express, Request, Response, NextFunction } from 'express';
import helmet from 'helmet';
import cors from 'cors';
import compression from 'compression';
import cookieParser from 'cookie-parser';
import { env, isDevelopment, isProduction } from '@/config/env';
import {
  bootstrap,
  healthCheck,
  isApplicationReady,
  BootstrapResult,
} from '@/core/kernel/bootstrap';

// -----------------------------------------------------------------------------
// Express Application Factory
// -----------------------------------------------------------------------------

/**
 * Creates and configures the Express application.
 *
 * @param bootstrapResult - Result from application bootstrap
 * @returns Configured Express application
 */
function createApp(bootstrapResult: BootstrapResult): Express {
  const app = express();

  // Trust proxy for accurate IP detection behind reverse proxy
  if (isProduction()) {
    app.set('trust proxy', 1);
  }

  // View engine setup (EJS templates)
  app.set('view engine', 'ejs');
  app.set('views', './src/views');

  // Security middleware
  app.use(
    helmet({
      contentSecurityPolicy: isDevelopment() ? false : undefined,
      crossOriginEmbedderPolicy: false,
    })
  );

  // CORS configuration
  app.use(
    cors({
      origin: env.CORS_ORIGIN,
      credentials: true,
      methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
      allowedHeaders: ['Content-Type', 'Authorization', 'X-Requested-With'],
    })
  );

  // Body parsing
  app.use(express.json({ limit: '10mb' }));
  app.use(express.urlencoded({ extended: true, limit: '10mb' }));

  // Cookie parsing
  app.use(cookieParser());

  // Compression for responses
  app.use(compression());

  // Static files
  app.use('/public', express.static('public'));
  app.use('/uploads', express.static(env.UPLOAD_DIR));

  // Request logging in development
  if (isDevelopment()) {
    app.use((req: Request, _res: Response, next: NextFunction) => {
      const timestamp = new Date().toISOString();
      // eslint-disable-next-line no-console
      console.log(`[${timestamp}] ${req.method} ${req.url}`);
      next();
    });
  }

  // Health check endpoints
  app.get('/health', async (_req: Request, res: Response) => {
    const health = await healthCheck();
    const statusCode = health.healthy ? 200 : 503;
    res.status(statusCode).json(health);
  });

  app.get('/health/ready', (_req: Request, res: Response) => {
    if (isApplicationReady()) {
      res.status(200).json({ ready: true });
    } else {
      res.status(503).json({ ready: false });
    }
  });

  app.get('/health/live', (_req: Request, res: Response) => {
    res.status(200).json({ alive: true });
  });

  // API version info
  app.get('/api', (_req: Request, res: Response) => {
    res.json({
      name: env.APP_NAME,
      version: '1.0.0',
      environment: env.NODE_ENV,
      documentation: '/api/docs',
    });
  });

  // Mount module routes
  // Routes will be registered by each module during activation
  // The module loader handles route registration through the router
  const moduleLoader = bootstrapResult.moduleLoader;
  const activeModules = moduleLoader.getActiveModules();

  // Log active module routes
  if (isDevelopment()) {
    // eslint-disable-next-line no-console
    console.log(`[Server] Mounting routes for ${activeModules.length} active modules`);
  }

  // TODO: Route mounting will be handled when module structure is complete
  // Each module will register its routes through the module loader

  // 404 handler
  app.use((_req: Request, res: Response) => {
    res.status(404).json({
      success: false,
      error: {
        code: 'NOT_FOUND',
        message: 'The requested resource was not found',
      },
    });
  });

  // Global error handler
  app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
    // eslint-disable-next-line no-console
    console.error('[Server] Unhandled error:', err);

    // Determine status code
    const statusCode = 'statusCode' in err ? (err as { statusCode: number }).statusCode : 500;

    // Don't expose internal error details in production
    const message = isProduction() ? 'An unexpected error occurred' : err.message;

    res.status(statusCode).json({
      success: false,
      error: {
        code: 'INTERNAL_ERROR',
        message,
        ...(isDevelopment() && { stack: err.stack }),
      },
    });
  });

  return app;
}

// -----------------------------------------------------------------------------
// Server Startup
// -----------------------------------------------------------------------------

/**
 * Starts the HTTP server.
 *
 * @param app - Express application
 * @param bootstrapResult - Bootstrap result for shutdown coordination
 * @returns HTTP server instance
 */
function startServer(
  app: Express,
  bootstrapResult: BootstrapResult
): import('http').Server {
  const port = env.PORT;
  const host = '0.0.0.0';

  const server = app.listen(port, host, () => {
    // eslint-disable-next-line no-console
    console.log('\n========================================');
    // eslint-disable-next-line no-console
    console.log(`  ${env.APP_NAME} Server Started`);
    // eslint-disable-next-line no-console
    console.log('========================================');
    // eslint-disable-next-line no-console
    console.log(`  URL: http://${host}:${port}`);
    // eslint-disable-next-line no-console
    console.log(`  Environment: ${env.NODE_ENV}`);
    // eslint-disable-next-line no-console
    console.log(`  Modules: ${bootstrapResult.status.services.modules} active`);
    // eslint-disable-next-line no-console
    console.log('========================================\n');

    if (isDevelopment()) {
      // eslint-disable-next-line no-console
      console.log('  Available endpoints:');
      // eslint-disable-next-line no-console
      console.log(`    - Health:     http://localhost:${port}/health`);
      // eslint-disable-next-line no-console
      console.log(`    - API Info:   http://localhost:${port}/api`);
      // eslint-disable-next-line no-console
      console.log(`    - Admin:      http://localhost:${port}/admin`);
      // eslint-disable-next-line no-console
      console.log('');
    }
  });

  // Handle server errors
  server.on('error', (error: NodeJS.ErrnoException) => {
    if (error.code === 'EADDRINUSE') {
      // eslint-disable-next-line no-console
      console.error(`[Server] Port ${port} is already in use`);
    } else if (error.code === 'EACCES') {
      // eslint-disable-next-line no-console
      console.error(`[Server] Permission denied to bind to port ${port}`);
    } else {
      // eslint-disable-next-line no-console
      console.error('[Server] Failed to start:', error);
    }
    process.exit(1);
  });

  // Graceful shutdown handling
  const gracefulShutdown = async (signal: string): Promise<void> => {
    // eslint-disable-next-line no-console
    console.log(`\n[Server] Received ${signal}, starting graceful shutdown...`);

    // Stop accepting new connections
    server.close(async () => {
      // eslint-disable-next-line no-console
      console.log('[Server] HTTP server closed');

      // Shutdown application services
      await bootstrapResult.shutdown();

      // eslint-disable-next-line no-console
      console.log('[Server] Graceful shutdown complete');
      process.exit(0);
    });

    // Force shutdown after 30 seconds
    setTimeout(() => {
      // eslint-disable-next-line no-console
      console.error('[Server] Forced shutdown after timeout');
      process.exit(1);
    }, 30000);
  };

  // Register signal handlers
  process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
  process.on('SIGINT', () => gracefulShutdown('SIGINT'));

  return server;
}

// -----------------------------------------------------------------------------
// Main Entry Point
// -----------------------------------------------------------------------------

/**
 * Main application entry point.
 * Orchestrates bootstrap, app creation, and server startup.
 */
async function main(): Promise<void> {
  try {
    // Bootstrap the application
    const bootstrapResult = await bootstrap({
      onReady: () => {
        if (isDevelopment()) {
          // eslint-disable-next-line no-console
          console.log('[Main] Bootstrap complete, creating Express server...');
        }
      },
    });

    // Create and configure Express app
    const app = createApp(bootstrapResult);

    // Start the HTTP server
    startServer(app, bootstrapResult);
  } catch (error) {
    // eslint-disable-next-line no-console
    console.error('\n========================================');
    // eslint-disable-next-line no-console
    console.error('  FATAL: Application failed to start');
    // eslint-disable-next-line no-console
    console.error('========================================');
    // eslint-disable-next-line no-console
    console.error(error instanceof Error ? error.message : 'Unknown error');
    // eslint-disable-next-line no-console
    console.error('========================================\n');
    process.exit(1);
  }
}

// Run the application
main();

// Export for testing
export { createApp, startServer };
